/**
 * Activity Logging & Notes Engine for Rani Beauty Clinic CRM
 *
 * Note types: call, email, text, in-person, internal.
 * Supports client timeline, auto-generated notes, templates, mentions, pinning.
 */

import type {
  CRMNote,
  NoteType,
  NoteTemplate,
  NoteAttachment,
  ClientTimeline,
  TimelineEvent,
  TimelineEventType,
} from '@/types/crm';

// ─────────────────────────────────────────────────────────────
// NOTE CREATION
// ─────────────────────────────────────────────────────────────

/**
 * Create a new CRM note.
 */
export function createNote(input: {
  clientId: string;
  clientName: string;
  type: NoteType;
  subject: string;
  content: string;
  createdBy: string;
  isPinned?: boolean;
  mentions?: string[];
  tags?: string[];
  attachments?: NoteAttachment[];
  automationId?: string;
  isAutoGenerated?: boolean;
}): CRMNote {
  const now = new Date().toISOString();
  return {
    id: `note_${Date.now()}_${Math.random().toString(36).slice(2, 8)}`,
    clientId: input.clientId,
    clientName: input.clientName,
    type: input.type,
    subject: input.subject,
    content: input.content,
    createdBy: input.createdBy,
    createdAt: now,
    updatedAt: now,
    isPinned: input.isPinned || false,
    mentions: input.mentions || [],
    tags: input.tags || [],
    attachments: input.attachments || [],
    automationId: input.automationId,
    isAutoGenerated: input.isAutoGenerated || false,
  };
}

/**
 * Create an auto-generated note from a system event.
 */
export function createAutoNote(
  clientId: string,
  clientName: string,
  event: string,
  details: string,
  automationId?: string,
): CRMNote {
  return createNote({
    clientId,
    clientName,
    type: 'internal',
    subject: event,
    content: details,
    createdBy: 'system',
    isAutoGenerated: true,
    automationId,
    tags: ['auto_generated'],
  });
}

// ─────────────────────────────────────────────────────────────
// NOTE MANAGEMENT
// ─────────────────────────────────────────────────────────────

/**
 * Pin or unpin a note.
 */
export function togglePin(note: CRMNote): CRMNote {
  return {
    ...note,
    isPinned: !note.isPinned,
    updatedAt: new Date().toISOString(),
  };
}

/**
 * Update a note's content.
 */
export function updateNote(
  note: CRMNote,
  updates: { subject?: string; content?: string; tags?: string[]; mentions?: string[] },
): CRMNote {
  return {
    ...note,
    ...updates,
    updatedAt: new Date().toISOString(),
  };
}

/**
 * Add a mention to a note.
 */
export function addMention(note: CRMNote, mention: string): CRMNote {
  if (note.mentions.includes(mention)) return note;
  return {
    ...note,
    mentions: [...note.mentions, mention],
    updatedAt: new Date().toISOString(),
  };
}

